code.C:
#include <stdio.h>
int main() {
    int n, m;
    scanf("%d %d", &n, &m);
    int count = 0;
    while (n != m) {
        if (n > m) {
            n /= 2;
        } else {
            n *= 2;
        }
        count++;
    }
    printf("%d\n", count);
    return 0;
}

