code.JavaScript:
const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
rl.on('line', (input) => {
    const [n, m] = input.split(' ').map(Number);
    let count = 0;
    while (n !== m) {
        if (n > m) {
            n = Math.floor(n / 2);
        } else {
            n *= 2;
        }
        count++;
    }
    console.log(count);
});

